class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        def max_height(r, b):
            height = 0
            while True:
                if height % 2 == 0:
                    if r >= height + 1:
                        r -= height + 1
                        height += 1
                    else:
                        break
                else:
                    if b >= height + 1:
                        b -= height + 1
                        height += 1
                    else:
                        break
            return height

        return max(max_height(red, blue), max_height(blue, red))
